// Extract payload and format email body
const payload = $json;
const disruption = payload.disruption || {};
const optimizer = payload.optimizer_summary || {};
const diversions = payload.diversion_orders || [];
const holds = payload.hold_orders || [];

let emailBody = `
<h2>🚨 NexusRecover IRROPS Plan Activated</h2>
<p><strong>Disruption:</strong> ${disruption.event || 'Unknown'}</p>
<p><strong>Hub:</strong> ${disruption.hub_airport || 'YYZ'}</p>

<h3>Capacity Impact</h3>
<ul>
  <li>Nominal capacity: ${disruption.runway_capacity_nominal_arr_per_hr || 12} arr/hr</li>
  <li>Storm capacity: ${disruption.runway_capacity_storm_arr_per_hr || 4} arr/hr</li>
  <li>Reduction: ${disruption.capacity_reduction_pct || 67}%</li>
</ul>

<h3>Optimizer Decision Summary</h3>
<ul>
  <li>Baseline cost: $${optimizer.baseline_cost_usd?.toLocaleString() || 0}</li>
  <li>Optimized cost: $${optimizer.optimized_cost_usd?.toLocaleString() || 0}</li>
  <li>Savings: $${optimizer.savings_usd?.toLocaleString() || 0} (${optimizer.savings_pct || 0}%)</li>
  <li>PAX protected: ${optimizer.pax_groups_protected || 0}</li>
  <li>PAX stranded: ${optimizer.pax_groups_stranded || 0}</li>
  <li>Flights held: ${optimizer.flights_held || 0}</li>
  <li>Flights diverted: ${optimizer.flights_diverted || 0}</li>
</ul>

<h3>⚠️ DIVERSION ORDERS (${diversions.length})</h3>
`;

for (const div of diversions) {
  emailBody += `
  <div style="border: 1px solid #ddd; padding: 10px; margin: 10px 0; border-radius: 4px;">
    <p><strong>${div.flight_id}</strong> → ${div.to_airport} (${div.to_airport_name})</p>
    <p>ETA: ${div.eta_at_alternate} | PAX: ${div.total_pax_onboard} (Biz: ${div.pax_breakdown?.business || 0}, Eco: ${div.pax_breakdown?.economy || 0})</p>
    <p><strong>Contacts to notify:</strong></p>
    <ul>
      ${div.contacts_to_notify?.map(c => `<li>${c}</li>`).join('') || ''}
    </ul>
    <p><strong>Ground ops required:</strong></p>
    <ul>
      ${div.ground_ops_required?.map(g => `<li>${g}</li>`).join('') || ''}
    </ul>
  </div>
  `;
}

emailBody += `
<h3>🛬 DEPARTURE HOLD ORDERS (${holds.length})</h3>
`;

for (const hold of holds) {
  emailBody += `
  <div style="border: 1px solid #ddd; padding: 10px; margin: 10px 0; border-radius: 4px;">
    <p><strong>${hold.flight_id}</strong> to ${hold.destination}</p>
    <p>Original ETD: ${hold.original_etd} → Revised ETD: ${hold.revised_etd} (+${hold.delay_applied_min}m hold)</p>
    <p>Protecting ${hold.connecting_pax_protected} connecting PAX | Hold cost: $${hold.hold_cost_usd?.toLocaleString() || 0}</p>
  </div>
  `;
}

emailBody += `
<hr />
<p><small>Issued at: ${payload.issued_at_utc} | System: ${payload.issued_by}</small></p>
`;

return {
  email_body: emailBody,
  payload: payload
};
